---- MODULE TwoPhaseCommit ----
EXTENDS Integers, Sequences, FiniteSets

CONSTANT N, FiniteSet

VARIABLES participants, coordinator, messages

TypeOK == /\ participants \in FiniteSet(N)
          /\ coordinator \in N
          /\ messages \in FiniteSet({Prepare, VoteYes, VoteNo, Commit, Abort})

Init == /\ participants = {}
          /\ coordinator = 1
          /\ messages = {}

Next == 
  \/ /\ participants = {}
        /\ messages = {}
        /\ \A p \in N \setminus {coordinator} : 
              /\ messages' = messages \cup {Prepare(p)}
          /\ participants' = participants \cup {coordinator}
  \/ /\ participants = {coordinator}
        /\ \A p \in N \setminus {coordinator} : 
              /\ messages' = messages \cup {VoteYes(p)}
          /\ participants' = participants
  \/ /\ participants = {coordinator}
        /\ \A p \in N \setminus {coordinator} : 
              /\ messages' = messages \cup {VoteNo(p)}
          /\ participants' = participants
  \/ /\ participants = {coordinator}
        /\ messages' = messages \cup {Commit}
          /\ participants' = participants
  \/ /\ participants = {coordinator}
        /\ messages' = messages \cup {Abort}
          /\ participants' = participants

Spec == Init /\ [][Next]_<<participants, coordinator, messages>>

====
